'use client';

type Props = {
  label: string;
  value: string;
};

export default function StatGlassCard({ label, value }: Props) {
  return (
    <div className='relative w-full group'>
      <div
        className='
          relative z-10
          w-full h-full
          rounded-2xl
          bg-white/5
          backdrop-blur-sm
          border border-black/10
          shadow-[0_8px_32px_rgba(0,0,0,0.08)]
          p-5
          flex
          flex-col
          justify-center
          items-center
          text-center
          transition
          duration-300
          group-hover:scale-[1.02]
        '
      >
        {/* VALUE */}
        <h3 className='text-xl sm:text-2xl font-semibold text-black/70 break-words'>
          {value}
        </h3>

        {/* LABEL */}
        <p className='text-sm sm:text-base text-gray/600 mt-1 break-words'>
          {label}
        </p>
      </div>
    </div>
  );
}
